if [[ "$*" == *ssrFunc* ]]
then
    target=x86sim
    ipfs=(2 3 4 5)
    ssrs=(2 3 4 5 6 7 8)
    casc_len=(1 2 3)
    for ip in "${ipfs[@]}"; do
        for ssr in "${ssrs[@]}"; do
            for cl in "${casc_len[@]}"; do

            if [[ $ip == $ssr ]]; then

                echo "ip = ssr"
            else
                let "flen=($ip * $ssr * $cl * 2)"
                let "ws=($ip * $ssr * $cl * 128)"

                test_arr[$LINENO]="make all DATA_TYPE=cint16 COEFF_TYPE=int16  TARGET=$target FIR_LEN=$flen INTERPOLATE_FACTOR=$ip CASC_LEN=$cl SHIFT=16 INPUT_WINDOW_VSIZE=$ws PORT_API=1 RESULTS_PATH=./results/func_ssr"
            fi
            done
        done
    done #fLen
fi
